INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'overview', 'Overview > IIIT Manipur (Indian Institute of Information Technology Senapati, Manipur) is an Institute of National Importance by Act of Parliament, Government of India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'overview', 'Overview > The permanent campus is under construction. The temporary campus runs near National Highway 39, Mantripukhri, Heingang, Manipur 795002.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'overview', 'Overview > The temporary campus is surrounded by State government buildings like Police Headquarters, High Court, CRPF Camp. It is in a calm location surrounded by mountains.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'hostels_boys', 'Hostels Boys > There are 7 main boys hostels HB 1 to HB 7 inside campus. Each has minimum 12 rooms with maximum 4 people per room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'hostels_boys', 'Hostels Boys > KMR Hostel is 2km away from campus. It has 6 floors with 14 rooms per floor. Maximum 2 people per room. Bus is provided for students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'hostels_boys', 'Hostels Boys > Mantripukhri Hostel is 300m away from campus. It has 5 floors. Number of students per room depends on the room allotted.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'hostels_girls', 'Hostels Girls > There are 2 girls hostels within the campus. Each has 3 floors with 6 rooms per floor. Sharing is based on room allotted.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Timings: Breakfast Regular 7:00-9:00 AM, Holidays 7:30-9:30 AM. Lunch 12:00-2:00 PM. Snacks 4:30-5:30 PM. Dinner 7:00-9:00 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Both Veg and Non-Veg menus are available. Separate mess menus for vegetarian and non-vegetarian students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Monday: Breakfast - Mysore Bonda, Halwa/Pongal, Cornflakes, Fruit. Lunch - Rice, Roti, Cauliflower Aloo Curry, Palak Corn, Dal Tadka. Snacks - Tea, Namkeen. Dinner - Rice, Roti, Dal, Vegetable Fry, Papad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Tuesday: Breakfast - Idli, Sambhar, Chutney, Vada, Cornflakes, Fruit. Lunch - Rice, Roti, Dal, Manchurian, Aloo Tamatar, Papad, Raita. Snacks - Tea, Macaroni/Noodles. Dinner - Rice, Roti, Dal, Cauliflower Fry, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Wednesday: Breakfast - Puri, Matar Curry. Lunch - Jeera Rice, Roti, Dal, Paneer (6pc), Capsicum Gravy. Snacks - Tea, Pani Puri. Dinner - Rice, Roti, Dal, Chole, Papad, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Thursday: Breakfast - Aloo Paratha (2pcs), Curd, Ketchup, Fruit. Lunch - Rice, Roti, Mushroom Curry, Dal Makhani. Snacks - Tea, Biscuits. Dinner - Rice, Roti, Dal, Sev Tamatar, Papad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Friday: Breakfast - Puri, Chole, Fruit. Lunch - Pulao Rice, Roti, Dal, Curd, Palak Paneer, Aloo Methi. Snacks - Tea, Namkeen. Dinner - Rice, Roti, Dal, Cauliflower Aloo fry, Papad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Saturday: Breakfast - Uthappam/Dosa, Cornflakes, Chutney, Sambar. Lunch - Rice, Roti, Dal, Rajma Masala, Raita, Papad. Snacks - Tea, Mini Baked Samosa. Dinner - Rice, Roti, Aloo Fry, Dal Makhani, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Veg Sunday: Breakfast - Bread, Butter, Peanut Butter, Cornflakes, Poha/Pongal. Lunch - Roti, Dal, Vegetable Biryani, Capsicum Gravy, Curd. Snacks - Tea, Biscuits. Dinner - Rice, Roti, Rasam, Aloo Methi, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Monday: Breakfast - Mysore Bonda, Halwa/Pongal, Cornflakes, Omelette/Boiled Egg/Egg Bhurji. Lunch - Rice, Roti, Cauliflower Aloo Curry, Chicken Curry, Dal Tadka. Dinner - Rice, Roti, Dal, Vegetable Fry.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Tuesday: Breakfast - Idli, Sambhar, Chutney, Vada, Cornflakes, Boiled Egg. Lunch - Rice, Roti, Dal, Fish Curry, Curd, Aloo Tomato Curry, Papad. Dinner - Rice, Roti, Dal, Cauliflower Fry, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Wednesday: Breakfast - Puri, Matar Curry. Lunch - Jeera Rice, Roti, Dal, Mutton Curry, Capsicum Gravy. Dinner - Rice, Roti, Dal, Chole, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Thursday: Breakfast - Aloo Paratha (2pcs), Curd, Ketchup. Lunch - Rice, Roti, Egg Curry, Dal Makhani, Papad. Dinner - Rice, Roti, Dal, Sev Tamatar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Friday: Breakfast - Bread, Butter, Omelette/Egg Bhurji/Boiled Egg. Lunch - Pulao Rice, Roti, Dal, Curd, Butter Chicken/Chicken Curry, Aloo Methi. Dinner - Rice, Roti, Dal, Cauliflower Aloo fry.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Saturday: Same as Veg Saturday menu.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Non-Veg Sunday: Breakfast - Bread, Butter, Peanut Butter, Cornflakes, Poha/Pongal, Fruits. Lunch - Roti, Dal, Curd, Capsicum Gravy, Biryani/Pulao Rice, Chicken Curry (alternative weeks). Dinner - Rice, Roti, Dal, Aloo Methi, Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'mess', 'Mess > Notes: Availability of fruits and vegetables according to seasons. Wasting of food will lead to fine.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Semester 1 Institute Fee Total: Rs 1,61,900 (includes Admission Fee 5000, Tuition 1,40,000, Exam Fee 2400, Gymkhana 2000, Caution Money 10000 refundable, Medical Insurance 2500).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Semester 1 Mess/Hostel Fee Total: Rs 63,000 (includes Mess Deposit 5000 refundable, Hall Mess Establishment 1000, Hostel Rent 8000, Fan/Elec/Water 2000, Hostel Fund 2000, Mess Advance 45000).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Semester 1 Grand Total: Rs 2,24,900.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Semester 2 Grand Total: Rs 2,01,400. Institute Fee: 1,44,400. Mess/Hostel Fee: 57,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Tuition Fee per semester: Rs 1,40,000. This is the same for all 8 semesters.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Hostel Rent per semester: Rs 8,000. Mess Advance per semester: Rs 45,000 (Rs 9000 x 5 months).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > One-time fees: Admission Fee 5000, Institute Caution Money 10000 (refundable), Mess Deposit 5000 (refundable), Hall Mess Establishment 1000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Medical Insurance: Rs 2500 per year (paid in odd semesters only).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Alumni subscription fee: Rs 6000 (one-time, charged in Semester 4).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Convocation Fee: Rs 6000 (one-time, charged in Semester 8).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fee_structure', 'Fee Structure > Note: There is NO concession in fees for OBC/SC/ST/PD/EWS or any other category of students. GST extra when applicable.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'wifi', 'WiFi > Every hostel has Jio 5G WiFi with decent speed.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'attendance', 'Attendance > 75% attendance mandatory for every examination in every subject.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'clubs', 'Clubs > Technical Clubs: VIDYUT Club (VLSI/Embedded Systems, chip design, hardware projects), SYNAPSE Club (AI/ML/Data Science, hackathons), Coding Club (DSA, competitive programming, interview prep), Cyber Security Club (CTFs, ethical hacking), Android Development Club (mobile app dev), Cloud Computing Club (AWS, DevOps), Mathematica Club (math, simulations), Web Development Club (frontend+backend).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'clubs', 'Clubs > Cultural Clubs: YouTube X Film Making Club, Photography Club IIIT-M, Sketchers Studio (Art), Octavia (Music Club), Stand-up IIITM (Comedy), Fashion Fusion Club.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'clubs', 'Clubs > Additional Clubs: Qurbat (Community bonding, social events), Darshanam (Literature & Debate, public speaking), Readers Club (book reviews, reading sessions).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fests', 'Fests > Ahouba is the annual fest of IIIT Manipur. Usually happens for 3 days. Popular singers and bands are invited.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'fests', 'Fests > Ahouba has technical events (coding contests, hackathons, project showcases by Coding Club, SYNAPSE, VIDYUT) and cultural events (music, dance, stand-up, fashion shows). Dance and singing competitions with cash prizes. Food stalls across campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'sports', 'Sports > Available: Football, E-Sports, Badminton, Chess, Kabaddi, Table Tennis, Athletics, Volleyball, Cricket, Basketball.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'sports', 'Sports > Facilities: Common ground for Cricket and Football, 2 Badminton courts, 1 Basketball court, 2 Table Tennis setups, 2 Volleyball courts.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'canteen', 'Canteen/Shops > A3 mart (200m from campus) for groceries, many other shops nearby. Fruit and vegetable market 200m away from campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'canteen', 'Canteen/Shops > Swiggy and Zomato available till 9pm, delivery done till the Boys Hostel.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'gym', 'Gym > No gym inside campus. A gym is located in front of campus where many students go. Monthly fee around Rs 1000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'medical', 'Medical > No clinic inside campus, only basic first aid facilities. Students given medical insurance which can be used to claim expenses.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'elections', 'Elections > Done once in 2 semesters. Some positions reserved for specific category of students based on Year and Gender.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'transport', 'Transport > Nearest airport: Imphal Airport (12 km from institute). Nearest railway stations: Dimapur (190 km) and Guwahati (450 km).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'restaurants', 'Restaurants > Near campus: KK South Indian Cafe and D4 Cafe are the most visited. After 3km: Dominos, KFC, Le Zara, Blue Moon, Pizza Hut. Many options on Swiggy and Zomato.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'nearby_places', 'Nearby Places > Tourist: 1. Marjing Polo Statue (worlds tallest equestrian polo statue, 5.3km). 2. Kangla Fort (old fortified palace, 4km). 3. Langol Hills Peak (trekking spot just behind campus). 4. Loktak Lake (freshwater lake, 50km).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'nearby_places', 'Nearby Places > Malls: 1. Mamcy Mall (3km, has KFC). 2. Kumecs City Centre (10km, has Vishal Mart). 3. Bazaar India Rudraksha Mall. 4. Airport Shopping Mall (10km).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'nearby_places', 'Nearby Places > Many waterfalls nearby but mostly closed due to security concerns.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'language_climate', 'Language > Campus people speak English and Hindi. Locals (shopkeepers, auto drivers) also understand English and Hindi clearly.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'language_climate', 'Climate > Average: 25C morning, 15C night. Winter: 18C morning, 5-6C late nights, heavy fog. Summer: 25-30C morning, 20-22C nights. Heavy rains during monsoon.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'campus', 'Fines > Students not usually fined unless matter reaches Director level. Loss of ID card: Rs 10,000 fine. Serious indiscipline: Rs 10,000 fine.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Manipur', 'laundry', 'Laundry > No specific laundry service mentioned by ambassador. Data gap — needs follow-up.');
